import React, { useState } from 'react';

const EditPurchase = ({ purchase, handleUpdate }) => {
  const [updatedPurchase, setUpdatedPurchase] = useState({
    ...purchase,
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setUpdatedPurchase((prevPurchase) => ({
      ...prevPurchase,
      [name]: value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    handleUpdate(updatedPurchase);
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label>Location:</label>
        <input type="text" name="location" value={updatedPurchase.location} onChange={handleChange} required />
      </div>
      <div>
        <label>Material ID:</label>
        <input type="text" name="materialid" value={updatedPurchase.materialid} onChange={handleChange} required />
      </div>
      <div>
        <label>Material Name:</label>
        <input type="text" name="name" value={updatedPurchase.name} onChange={handleChange} required />
      </div>
      <div>
        <label>Quantity:</label>
        <input type="text" name="quantity" value={updatedPurchase.quantity} onChange={handleChange} required />
      </div>
      <div>
        <label>Price:</label>
        <input type="text" name="price" value={updatedPurchase.price} onChange={handleChange} required />
      </div>
      <div>
        <label>Vendor:</label>
        <input type="text" name="vendor" value={updatedPurchase.vendor} onChange={handleChange} required />
      </div>
      <div>
        <label>Date:</label>
        <input type="text" name="date" value={updatedPurchase.date} onChange={handleChange} required />
      </div>
      <button type="submit">Save</button>
    </form>
  );
};

export default EditPurchase;
